#include <stdio.h>
#include <stdbool.h>

bool isArmstrong(int num) {
    int originalNum = num, result = 0;
    while (originalNum != 0) {
        int remainder = originalNum % 10;
        result += remainder * remainder * remainder;
        originalNum /= 10;
    }
    return result == num;
}

int main() {
    if (isArmstrong(371)) printf("Yes\n");
    return 0;
}
